// // This module implements a 1-bit DRAM cell with a data input (D), a word line (WL), a bit line (BL), and a read/write control line (RW). When RW is high, the data should be read from the cell when WL is high, and the output should be reflected on BL.
module dram_cell (
    input wire D,     // Data input
    input wire WL,    // Word line (activate line)
    input wire RW,    // Read/Write control
    output reg BL     // Bit line (output)
);

    reg stored_bit; // Internal storage for the 1-bit DRAM cell

    always @(posedge WL) begin
        if (RW) begin
            // Write operation
            stored_bit <= D; 
        end else begin
            // Read operation
            BL <= stored_bit; 
        end
    end
endmodule
